customEChartConfig:
{{ ((chartType) => ( 
(() => {
  const raw = Renewal_List.filteredTableData || Renewal_List.tableData || [];
  const counts = raw.reduce((acc, r) => {
    const keyRaw = (r.Status ?? '').toString().trim();
    const key = keyRaw ? keyRaw : 'No Status';
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});

  const entriesSorted = Object.entries(counts).sort(([, a], [, b]) => b - a);
  const labels = entriesSorted.map(([name]) => name);

  // Gleiche Farbdefinitionen wie zuvor (inkl. Hellgrau für "No Status")
  const colors = {
    'At Risk': '#e53935',      // Rot
    'Low Risk': '#AEEA00',     // Lime (hell)
    'Closed Won': '#22b31e',   // Dunkelgrün
    'Renewal Lost': '#424242', // Dunkelgrau
    'No Status': '#CCCCCC'     // Hellgrau, gut sichtbar auf weiß
  };

  return {
    tooltip: {
      trigger: 'item',
      formatter: '{b}: {c}'
    },
    grid: {
      left: '30%',
      right: '10%',
      top: '5%',
      bottom: '5%',
      containLabel: false
    },
    xAxis: { type: 'value', show: false },
    yAxis: {
      type: 'category',
      show: true,
      axisLine: { show: false },
      axisTick: { show: false },
      axisLabel: { show: true, color: '#333', fontSize: 12 },
      data: labels
    },
    series: [{
      type: 'bar',
      label: {
        show: true,
        position: 'inside',
        formatter: '{c}',
        color: '#fff',
        fontWeight: 'bold'
      },
      data: entriesSorted.map(([name, value]) => ({
        value,
        name,
        itemStyle: {
          color: colors[name] || '#CCCCCC' // Fallback konsistent
        }
      }))
    }]
  };
})()
))(RiskChart.chartType) }}
